       (PAR_EN), .Prescale (Prescale), .edge_cnt (edge_cnt), .bit_cnt
       (bit_cnt), .par_err (n_12), .strt_glitch (strt_glitch), .stp_err
       (n_11), .dat_samp_en (dat_samp_en), .enable (UNCONNECTED21),
